var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그 기계야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきたあのマシンだからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this machine, that you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，它是必不可少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그 기계와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まであのマシンとともにいることを。`,ENG:`that you'll be with it, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和它一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called it to your office. It said it'd be here soon.`,TWN:`做好心理準備後，你將它傳喚到老闆辦公室，它說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:`ANTIAIR_FOX_NULL_NULL`,text:{KOREA:`귀하의 종신계약 권유에 대한 답을 산출하는 중.`,JPN:`終身契約勧誘への回答を算出中。`,ENG:`Looking for an appropriate answer to your lifetime contract offer....`,TWN:`對於您「終身契約」的提議，正在計算答案……`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ANTIAIR_FOX_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`ANTIAIR_FOX_NULL_NULL`,text:{KOREA:`......계약서는 쌍방협약이다. 한 쪽이 거부하면 성립이 불가능하다.`,JPN:`……契約書は双方協約によるものだ。一方が拒否すれば成立は不可能。`,ENG:`A contract is a mutual agreement. It can't be established if one of the parties rejects it.`,TWN:`……契約是雙方同意。有一方拒絕就無法成立。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ANTIAIR_FOX_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`ANTIAIR_FOX_NULL_NULL`,text:{KOREA:`기계에게 이런 선택을 맡기는 것은 위험한 행위다, 사장. 제1 원칙에도 위배된다.`,JPN:`マシンにこのような選択を任せることは危険な行為だ、社長。第1原則にも違反している。`,ENG:`You shouldn't let machines make a decision like this. You're also violating rule number 1.`,TWN:`讓機器做這種選擇，是很危險的行為，老闆。這也違反第一原則。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ANTIAIR_FOX_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`ANTIAIR_FOX_NULL_NULL`,text:{KOREA:`하지만......`,JPN:`しかし……`,ENG:`But...`,TWN:`但是……`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ANTIAIR_FOX_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`ANTIAIR_FOX_NULL_NULL`,text:{KOREA:`사장을 따르는 것은 객관적으로 판단했을 때도 이상적이다.`,JPN:`社長に従うことは、客観的に判断しても理想的だ。`,ENG:`Objectively, following you is the most reasonable decision.`,TWN:`跟隨老闆從客觀上來判斷，也是最理想的選擇。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ANTIAIR_FOX_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`ANTIAIR_FOX_NULL_NULL`,text:{KOREA:`본 기체는 이 계약에 이견이 없다.`,JPN:`本機はこの契約に異論を持たない。`,ENG:`I have no objection to this contract.`,TWN:`本機對該契約沒有異議。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ANTIAIR_FOX_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};